input.command:
hookdeck gateway transformation create \
  --name "drop-missing-field-zr-8jslvjl" \
  --code 'addHandler("transform", (request, context) => {
  const body = request.body;
  if (body === undefined || body === null || body.required_field === undefined) {
    throw new Error("Missing required_field in request body");
  }
  return request;
});' \
  --output json 2>&1

